import os
import git

def load_repo_context(repo_path: str, file_patterns: list = ['*.py']) -> str:
    repo = git.Repo(repo_path)
    context = f"Repo: {repo_path}\nBranch: {repo.active_branch}\n"

    for root, dirs, files in os.walk(repo_path):
        for file in files:
            if any(pattern in file for pattern in file_patterns):
                with open(os.path.join(root, file), 'r') as f:
                    context += f"File: {file}\n{f.read()}\n\n"
    return context[:4000]  # Truncate for token limits

import subprocess

class TestValidator:
    def __init__(self, repo_path: str):
        self.repo_path = repo_path

    def validate_changes(self, modified_files: list) -> dict:
        cmd = [
            'pytest',
            '-v',
            '--cov=src',
            '--cov-report=term-missing',
            *modified_files
        ]

        result = subprocess.run(
            cmd, 
            cwd=self.repo_path,
            capture_output=True, 
            text=True
        )

        return {
            'passed': result.returncode == 0,
            'coverage': self._parse_coverage(result.stdout),
            'output': result.stdout + result.stderr
        }

